output.sparql:
PREFIX ps: <http://www.wikidata.org/prop/statement/>
PREFIX pq: <http://www.wikidata.org/prop/qualifier/>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX p: <http://www.wikidata.org/prop/>
SELECT ?pop2000 ?pop2009 WHERE {
  {
    SELECT ?pop2000 WHERE {
      wd:Q368526 p:P1082 ?stmt .
      ?stmt ps:P1082 ?pop2000 ; pq:P585 ?time .
      FILTER(SUBSTR(STR(?time) , 1 , 4) = '2000')
    }
  }
  {
    SELECT ?pop2009 WHERE {
      wd:Q368526 p:P1082 ?stmt .
      ?stmt ps:P1082 ?pop2009 ; pq:P585 ?time .
      FILTER(SUBSTR(STR(?time) , 1 , 4) = '2009')
    }
  }
}
